package tpu_pkg;
    import uvm_pkg::*;
    `include "uvm_macros.svh"

    import tpu_checker_pkg::*;
    import apb_reg_pkg::*;
    import axi_rsp_pkg::*;
    import axi_data_pkg::*;
    import tpu_covergroup_pkg::*;
    
    class tpu_virtual_sequencer extends uvm_sequencer;
        data_sequencer   data_sqr;
        reg_sequencer    reg_sqr;
        rsp_sequencer    rsp_sqr;
        `uvm_component_utils(tpu_virtual_sequencer)
        
        function new(string name ="tpu_virtual_sequencer",uvm_component parent);
        super.new(name,parent);
        endfunction
    endclass:tpu_virtual_sequencer

    class tpu_env extends uvm_env;
        
        data_agent          data_agt;
        reg_agent           reg_agt;
        rsp_agent           rsp_agt;
        tpu_virtual_sequencer   virt_sqr;
        tpu_checker             cheker;
        tpu_covergroup         cvrg;
        //添加covergroup
        `uvm_component_utils(tpu_env)
        
        function new(string name = "tpu_env",uvm_component parent);
            super.new(name,parent);
        endfunction

        function void build_phase(uvm_phase phase);
            super.build_phase(phase);
            data_agt = data_agent::type_id::create("data_agt",this);
            rsp_agt = rsp_agent::type_id::create("rsp_agt",this);
            reg_agt = reg_agent::type_id::create("reg_agt",this);
            virt_sqr = tpu_virtual_sequencer::type_id::create("virt_sqr",this); 
            cheker =  tpu_checker::type_id::create("cheker",this);
            //创建covergroup
            cvrg = tpu_covergroup::type_id::create("cvrg",this);
        endfunction

        function void connect_phase (uvm_phase phase);
            super.connect_phase(phase);
            virt_sqr.reg_sqr  = reg_agt.sqr;
            virt_sqr.data_sqr = data_agt.sqr;
            virt_sqr.rsp_sqr  = rsp_agt.sqr;
            //monitor to scb
            data_agt.mon.mon_bp_port.connect(cheker.data_bp_imp);
            reg_agt.mon.mon_bp_port.connect(cheker.reg_bp_imp);
            rsp_agt.mon.mon_bp_port.connect(cheker.rsp_bp_imp);
        endfunction

    endclass

    class base_test extends uvm_test;
        `uvm_component_utils(base_test)
        local virtual axi_slave_intf  axi_sla_vif;
        local virtual axi_master_intf axi_mas_vif;
        local virtual apb_reg_intf    apb_reg_vif;
        tpu_env env;

        function new(string name = "base_test",uvm_component parent);
            super.new(name,parent);
        endfunction

        function void build_phase(uvm_phase phase);
            super.build_phase(phase);

            if(!uvm_config_db#(virtual axi_slave_intf)::get(this,"","axi_sla_vif",axi_sla_vif)) begin
                `uvm_fatal("[GETINTF]","base_test don't get axi_sla_vif")
            end
            if(!uvm_config_db#(virtual axi_master_intf)::get(this,"","axi_mas_vif",axi_mas_vif)) begin
                `uvm_fatal("[GETINTF]","base_test don't get axi_mas_vif")
            end
            if(!uvm_config_db#(virtual apb_reg_intf)::get(this,"","apb_reg_vif",apb_reg_vif)) begin
                `uvm_fatal("[GETINTF]","base_test don't get apb_reg_vif")
            end
            env=tpu_env::type_id::create("env",this);
        endfunction

        function void connect_phase(uvm_phase phase);
            super.connect_phase(phase);

            this.set_interface(
                axi_sla_vif,
                axi_mas_vif,
                apb_reg_vif);

        endfunction

        task run_phase(uvm_phase phase);
        // NOTE:: raise objection to prevent simulation stopping
        phase.raise_objection(this);
            this.run_top_virtual_sequence();
        // NOTE:: drop objection to request simulation stopping
        phase.drop_objection(this);
        endtask

        function void end_of_elaboration_phase(uvm_phase phase);
            super.end_of_elaboration_phase(phase);
            uvm_root::get().set_report_verbosity_level_hier(UVM_HIGH);
            uvm_root::get().set_timeout(10ms);
        endfunction

        virtual task run_top_virtual_sequence();
        // User to implement this task in the child tests
        endtask

        virtual function void set_interface(
            virtual axi_slave_intf axi_sla_vif,
            virtual axi_master_intf   axi_mas_vif,
            virtual apb_reg_intf   apb_reg_vif                        
        );//send interface to all agt;

            this.env.data_agt.set_interface(axi_sla_vif);
            this.env.rsp_agt.set_interface(axi_mas_vif);
            this.env.reg_agt.set_interface(apb_reg_vif);
            this.env.cheker.set_interface(apb_reg_vif);
            //添加covergroup
            this.env.cvrg.set_interface(axi_sla_vif,axi_mas_vif,apb_reg_vif);
        endfunction

    endclass:base_test


    class tpu_virtual_sequence extends uvm_sequence;
        data_sequence data_seq;
        rsp_sequence rsp_seq;
        reg_sequence    reg_seq;
        bit[1023:0]    matrix_a[];//打包好的矩阵
        bit[1023:0]    matrix_b[];
        bit[1023:0]    matrix_c[];
        bit data_done = 0; // 新增标志，表示数据发送完成
        `uvm_object_utils(tpu_virtual_sequence)
        `uvm_declare_p_sequencer(tpu_virtual_sequencer)//gua zai 

        function new (string name = "tpu_virtual_sequence");
        super.new(name);
        endfunction

        virtual task body();
            `uvm_info(get_type_name(), "=====================STARTED=====================", UVM_LOW)
            this.do_reg();//pei zhi reg
            this.matrix_pack();
            this.do_data();//fa song case_data
            data_done =1;
            `uvm_info("DATA_Done", "DATA_SEND_FINISHED", UVM_LOW)
            this.do_receiver();//jie shou data
            `uvm_info(get_type_name(), "=====================FINISHED=====================", UVM_LOW)
        endtask

        virtual task do_reg();

        endtask

        virtual task do_data();

        endtask

        virtual task do_receiver();

        endtask

        virtual task matrix_pack();
        

        endtask

    //////////////
    endclass:tpu_virtual_sequence

