    //fp32  m16n16k16官方
    class tpu_case16_sequence extends tpu_virtual_sequence;
        `uvm_object_utils(tpu_case16_sequence)

        function new(string name = "tpu_case16_sequence");
            super.new(name);
        endfunction
        //配置矩阵和数据类型
        task do_reg();
            `uvm_info("CASE0_SEQ", "Starting do_reg", UVM_LOW)
            `uvm_do_on_with(reg_seq, p_sequencer.reg_sqr, {pwdata[6:0] == 7'b0010110;})//m16n16k16 fp16类型
            `uvm_info("CASE0_SEQ", "Finished do_reg", UVM_LOW)                                          
        endtask

        task do_receiver();
            `uvm_info("CASE0_SEQ", "Starting do_receiver", UVM_LOW)
            `uvm_do_on_with(rsp_seq, p_sequencer.rsp_sqr, {aw_delay == 1; w_delay == 1; b_delay == 1;result_matrix_type == 2;})
            `uvm_info("CASE0_SEQ", "Finished do_receiver", UVM_LOW)
        endtask
        //配置awlen=行数-1;
        task do_data();
            `uvm_info("CASE0_SEQ", "Starting do_data", UVM_LOW)
            `uvm_do_on_with(data_seq, p_sequencer.data_sqr, {awaddr == 7'd0; 
                                                            awlen == 8'd15; 
                                                            awburst == 2'b01;
                                                            matrix_data.size() == local::matrix_a.size();  // 确保大小相同
                                                            foreach (local::matrix_a[i]) matrix_data[i] == local::matrix_a[i];}
                                                            )
            `uvm_do_on_with(data_seq, p_sequencer.data_sqr, {awaddr == 7'd32; 
                                                            awlen == 8'd15; 
                                                            awburst == 2'b01;
                                                            matrix_data.size() == local::matrix_b.size();  // 确保大小相同
                                                            foreach (local::matrix_b[i]) matrix_data[i] == local::matrix_b[i];}
                                                            )
            `uvm_do_on_with(data_seq, p_sequencer.data_sqr, {awaddr == 7'd64; 
                                                            awlen == 8'd15; 
                                                            awburst == 2'b01;
                                                            matrix_data.size() == local::matrix_c.size();  // 确保大小相同
                                                            foreach (local::matrix_c[i]) matrix_data[i] == local::matrix_c[i];}
                                                            )
            `uvm_info("CASE0_SEQ", "Finished do_data", UVM_LOW)

        endtask

